#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int ans = INT_MAX;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            int cnt = 0;
            while ((x & 1LL) == 0) { x >>= 1; ++cnt; }
            if (cnt < ans) ans = cnt;
        }
        printf("%d\n", ans);
    }
    return 0;
}

