#!/usr/bin/env python3
import sys

def trailing_zeros(x: int) -> int:
    cnt = 0
    while x % 2 == 0:
        x //= 2
        cnt += 1
    return cnt

def main():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        ans = 10**9
        for _ in range(n):
            x = int(next(it))
            cnt = 0
            while x & 1 == 0:
                x >>= 1
                cnt += 1
            if cnt < ans:
                ans = cnt
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

